#!/usr/bin/perl
use strict;
use warnings;
use Digest::MD5 qw(md5_hex);
use CGI;

my $cgi = new CGI;
my $password = $cgi->param('password');

if ($password) {
    my $hashed_password = md5_hex($password);
    print $cgi->header();
    print "Hashed password: $hashed_password\n";
} else {
    print $cgi->header();
